INSERT OR IGNORE INTO personality_question (id, text, keyed, domain, description_level_1, description_level_2, description_level_3, description_level_4, description_level_5) VALUES
  ('019e4f65-b566-7000-bb5d-230094f91487', 'Are you the life of the party?', 'plus', 'extraversion', 'You''d rather stay home with a book than be the center of attention. (Party? What party?)', 'You show up but mostly observe from the corner with snacks.', 'Sometimes you chat, sometimes you hide. Depends on the vibe and caffeine level.', 'You enjoy talking to people and usually have a good time at gatherings.', 'You walk in and the energy level immediately goes up. You ARE the party.'),
  ('019e4f65-b567-7001-9792-38718eb63ca7', 'Do you feel little concern for others?', 'minus', 'agreeableness', 'You cry during dog food commercials and offer help to strangers.', 'You generally care about people''s feelings.', 'You care… when it''s convenient and not too emotionally draining.', 'You mostly focus on your own stuff and don''t get too involved.', '"Not my circus, not my monkeys" is your life motto.'),
  ('019e4f65-b568-7002-9f3a-6f7862c09614', 'Are you always prepared?', 'plus', 'conscientiousness', 'You once showed up to a camping trip with only flip-flops and hope.', 'You usually wing it and somehow survive.', 'You prepare when it matters, otherwise… meh.', 'You like having a plan and backup plans.', 'Your backpack has a backpack. You''re prepared for the apocalypse.'),
  ('019e4f65-b569-7003-bb27-6fcaa4726ea0', 'Do you get stressed out easily?', 'plus', 'neuroticism', 'A flat tire is just an opportunity to practice patience.', 'You stay pretty calm even when things go wrong.', 'Stress happens, but you manage most of the time.', 'Small things can ruin your day pretty quickly.', 'Your brain treats "maybe" as a five-alarm fire.'),
  ('019e4f65-b56a-7004-aa55-47bbadd493e6', 'Do you have a rich vocabulary?', 'plus', 'openness', 'You call everything "thingy" or "whatchamacallit."', 'You know enough words but don''t flex them.', 'Average vocabulary, gets the job done.', 'You enjoy using precise and interesting words.', 'You dropped "sesquipedalian" in casual conversation… unironically.'),
  ('019e4f65-b56b-7005-8c8d-36f834a58ee0', 'Do you talk a lot?', 'plus', 'extraversion', 'You once went a whole day without saying more than 10 words.', 'You prefer listening over speaking.', 'You talk when you have something to say.', 'You''re quite chatty in most situations.', 'You talk so much your friends need a mute button.'),
  ('019e4f65-b56c-7006-a595-cc7b501cb336', 'Are you interested in people?', 'plus', 'agreeableness', 'People are exhausting. You''d rather talk to your plants.', 'You''re selective about whose life story you want to hear.', 'Some people yes, most people… maybe later.', 'You genuinely enjoy learning about others.', 'You''re the person who remembers everyone''s dog''s birthday.'),
  ('019e4f65-b56d-7007-85f3-977c267fcd50', 'Do you leave your belongings around?', 'minus', 'conscientiousness', 'Your desk looks like a minimalist Instagram photo.', 'You usually clean up after yourself.', 'Sometimes tidy, sometimes a mild disaster zone.', 'Things tend to pile up in creative locations.', 'You have a "floor wardrobe" and lost your keys… again.'),
  ('019e4f65-b56e-7008-8acb-845aecdca6fd', 'Are you relaxed most of the time?', 'minus', 'neuroticism', 'Your resting heart rate is "mild panic."', 'You get tense quite often.', 'Chill until something triggers you.', 'You stay pretty calm day-to-day.', 'Zen master level. Nothing fazes you.'),
  ('019e4f65-b56f-7009-bea4-43d1db0c6ff2', 'Do you have difficulty understanding abstract ideas?', 'minus', 'openness', 'You live in the world of metaphors and hypotheticals.', 'Abstract concepts are fun for you.', 'Depends on the topic.', 'You prefer concrete, practical ideas.', '"What does this even mean?" is your default reaction to philosophy.'),
  ('019e4f65-b570-700a-9b0a-e0bdc38d0910', 'Do you feel comfortable around people?', 'plus', 'extraversion', 'Social situations feel like being thrown into a shark tank.', 'You need time to warm up.', 'Comfortable with friends, awkward with strangers.', 'You generally feel at ease in social settings.', 'You could make friends with a lamppost.'),
  ('019e4f65-b571-700b-8700-7871f46d6009', 'Do you insult people?', 'minus', 'agreeableness', 'You''d rather compliment someone''s shoes than criticize them.', 'You avoid hurting others'' feelings.', 'Only when they really deserve it.', 'You can be blunt or sarcastic.', 'Your roasts could be a Netflix special.'),
  ('019e4f65-b572-700c-9f22-decdab954f1b', 'Do you pay attention to details?', 'plus', 'conscientiousness', 'You once put salt in your coffee twice.', 'Big picture person. Details are annoying.', 'You catch some details, miss others.', 'You notice the little things.', 'You spot typos from three rooms away.'),
  ('019e4f65-b573-700d-a1d9-a9ea1899a21a', 'Do you worry about things?', 'plus', 'neuroticism', 'You live in the moment. Tomorrow can worry about itself.', 'You worry only about important stuff.', 'Average worrier.', 'You tend to overthink possible bad outcomes.', 'You''ve already mentally rehearsed 47 disasters for next Tuesday.'),
  ('019e4f65-b574-700e-b6d4-d2478981b5c0', 'Do you have a vivid imagination?', 'plus', 'openness', 'Your daydreams are just about food and sleep.', 'Imagination is okay, but you stay realistic.', 'Sometimes you zone out creatively.', 'You often picture wild scenarios.', 'Your brain is a 4K IMAX theater running 24/7.'),
  ('019e4f65-b575-700f-8b00-2b9a58232962', 'Do you keep in the background?', 'minus', 'extraversion', 'You were born to be in the spotlight.', 'You enjoy being noticed.', 'Depends on the situation.', 'You prefer staying low-key.', 'You''re basically a ninja in social settings.'),
  ('019e4f65-b576-7010-ad62-4fe800209276', 'Do you sympathize with others'' feelings?', 'plus', 'agreeableness', '"Just stop crying and fix it" is your go-to advice.', 'You''re not the most empathetic person.', 'You sympathize sometimes.', 'You easily feel what others feel.', 'You absorb emotions like an emotional sponge.'),
  ('019e4f65-b577-7011-94f8-49cee8c0ee54', 'Do you make a mess of things?', 'minus', 'conscientiousness', 'You color-code your chaos and still make it look organized.', 'You rarely mess things up.', 'It happens occasionally.', 'Things tend to get disorganized around you.', 'You could turn a simple task into performance art of disaster.'),
  ('019e4f65-b578-7012-9994-e428b9aecb29', 'Do you seldom feel blue?', 'minus', 'neuroticism', 'You have seasonal depression… in all seasons.', 'You feel down fairly often.', 'Mood is usually stable.', 'You''re generally in a good mood.', 'You''re basically a walking ray of sunshine.'),
  ('019e4f65-b579-7013-b900-bf8fb1dab966', 'Are you not interested in abstract ideas?', 'minus', 'openness', 'You debate philosophy in the shower.', 'You enjoy deep, theoretical topics.', 'Sometimes yes, sometimes no.', 'You prefer practical over abstract.', '"If it''s not useful right now, I don''t care."'),
  ('019e4f65-b57a-7014-bc93-54839ebd2dda', 'Do you start conversations?', 'plus', 'extraversion', 'You wait for others to speak first… always.', 'You join conversations but rarely start them.', 'You start them when comfortable.', 'You easily initiate talks.', 'You could start a conversation with a rock.'),
  ('019e4f65-b57b-7015-b84a-2f5d1dd39115', 'Are you not interested in other people''s problems?', 'minus', 'agreeableness', 'You''re everyone''s unpaid therapist.', 'You care about others'' issues.', 'Depends on how close you are.', 'You prefer to stay out of drama.', '"That sounds like a you problem."'),
  ('019e4f65-b57c-7016-9382-6b8b8886de8e', 'Do you get chores done right away?', 'plus', 'conscientiousness', 'Procrastination is your love language.', 'You do them… eventually.', 'Sometimes immediately, sometimes later.', 'You usually finish chores quickly.', 'You finish chores before they even become chores.'),
  ('019e4f65-b57d-7017-a2cd-7dc53911aa76', 'Are you easily disturbed?', 'plus', 'neuroticism', 'You remain calm even when everything is on fire.', 'Small things rarely bother you.', 'You get annoyed sometimes.', 'You get disturbed pretty easily.', 'Everything bothers you. Everything.'),
  ('019e4f65-b57e-7018-a0b4-ee32f1a44911', 'Do you have excellent ideas?', 'plus', 'openness', 'Ideas? What ideas?', 'You get occasional decent ideas.', 'You have some good ideas now and then.', 'You often come up with creative ideas.', 'Your brain is a nonstop idea fireworks show.'),
  ('019e4f65-b57f-7019-9b2b-2dc051926e84', 'Do you have little to say?', 'minus', 'extraversion', 'You talk so much your friends need a mute button.', 'You''re quite chatty in most situations.', 'You talk when you have something to say.', 'You prefer listening over speaking.', 'You once went a whole day without saying more than 10 words.'),
  ('019e4f65-b580-701a-bc92-5a4b41c01951', 'Do you have a soft heart?', 'plus', 'agreeableness', 'You''re emotionally bulletproof.', 'You''re not easily moved.', 'You feel for others sometimes.', 'You''re quite compassionate.', 'Your heart is made of marshmallow.'),
  ('019e4f65-b581-701b-8d80-7e0eb569e72a', 'Do you often forget to put things back in their proper place?', 'minus', 'conscientiousness', 'Everything always goes back to its exact spot immediately.', 'You usually remember to tidy up.', 'You forget sometimes.', 'Things often stay where you left them.', 'Your room looks like a post-apocalyptic thrift store.'),
  ('019e4f65-b582-701c-83ae-e95eb81e14e2', 'Do you get upset easily?', 'plus', 'neuroticism', 'It takes a lot to upset you.', 'You stay calm most of the time.', 'You get irritated occasionally.', 'You get upset pretty easily.', 'Your emotional stability is held together by tape.'),
  ('019e4f65-b583-701d-9e62-72bb4392bdd1', 'Do you not have a good imagination?', 'minus', 'openness', 'Your imagination runs wild 24/7.', 'You have a pretty active imagination.', 'Average imagination.', 'You''re not very imaginative.', 'You think a potato is just a potato.'),
  ('019e4f65-b584-701e-bd10-66e06d8f773c', 'Do you talk to a lot of different people at parties?', 'plus', 'extraversion', 'You hug the wall like it''s your best friend.', 'You talk to a few people you already know.', 'You talk to some new people if the mood is right.', 'You enjoy chatting with many different people.', 'You''re the human equivalent of group chat.'),
  ('019e4f65-b585-701f-bbb9-03f224bb2781', 'Are you not really interested in others?', 'minus', 'agreeableness', 'You''re deeply curious about everyone''s life.', 'You care about others quite a bit.', 'You''re interested sometimes.', 'You''re not very interested in others.', 'Other people? What other people?'),
  ('019e4f65-b586-7020-b103-351c7b2ce2ba', 'Do you like order?', 'plus', 'conscientiousness', 'Chaos is your comfort zone.', 'Order is nice but not necessary.', 'You like some order.', 'You prefer things organized.', 'Your life runs on color-coded spreadsheets.'),
  ('019e4f65-b587-7021-9d45-4b76b4f38a6a', 'Do you change your mood a lot?', 'plus', 'neuroticism', 'Your mood is rock-solid.', 'Your mood is fairly stable.', 'Your mood changes sometimes.', 'Your mood changes quite often.', 'You have more mood swings than a playground.'),
  ('019e4f65-b588-7022-afea-4354acd0d3b3', 'Are you quick to understand things?', 'plus', 'openness', 'You need things explained multiple times.', 'You understand most things at normal speed.', 'You catch on fairly quickly.', 'You understand things fast.', 'You get it before the sentence is even finished.'),
  ('019e4f65-b589-7023-856f-2985d6415596', 'Do you avoid drawing attention to yourself?', 'minus', 'extraversion', 'You love being the center of attention.', 'You don''t mind attention.', 'Depends on the situation.', 'You prefer not to stand out.', 'You''d rather blend into the wallpaper.'),
  ('019e4f65-b58a-7024-ae2b-56fa119898e6', 'Do you take time out for others?', 'plus', 'agreeableness', 'Your time is strictly yours.', 'You help when it''s easy.', 'You help when you can.', 'You often make time for others.', 'You''d drop everything to help someone.'),
  ('019e4f65-b58b-7025-bbf7-a316e9897680', 'Do you shirk your duties?', 'minus', 'conscientiousness', 'You never avoid responsibilities.', 'You rarely avoid duties.', 'You avoid them sometimes.', 'You often put off responsibilities.', 'Duties? What duties?'),
  ('019e4f65-b58c-7026-9e61-c6bde0d9348a', 'Do you have frequent mood swings?', 'plus', 'neuroticism', 'Your mood is extremely stable.', 'Your mood doesn''t swing much.', 'You have occasional mood changes.', 'Your mood swings quite a bit.', 'You have more mood swings than a playground.'),
  ('019e4f65-b58d-7027-b49e-d64efb374328', 'Do you use difficult words?', 'plus', 'openness', 'You keep your words simple.', 'You use normal vocabulary.', 'You use some advanced words.', 'You enjoy using sophisticated words.', 'You use words that make dictionaries nervous.'),
  ('019e4f65-b58e-7028-a059-2c9e18a89cb9', 'Do you mind being the center of attention?', 'minus', 'extraversion', 'Being the center of attention feels terrifying.', 'You''d rather not be noticed.', 'It depends on the situation.', 'You''re okay with attention.', 'You love being in the spotlight.'),
  ('019e4f65-b58f-7029-9ca1-062e7d8dc170', 'Do you feel others'' emotions?', 'plus', 'agreeableness', 'You rarely notice how others feel.', 'You notice emotions sometimes.', 'You can usually tell how people feel.', 'You easily pick up on others'' emotions.', 'You feel other people''s emotions more than your own.'),
  ('019e4f65-b590-702a-bb41-5e1924246952', 'Do you follow a schedule?', 'plus', 'conscientiousness', 'A schedule? That''s cute.', 'You follow a loose plan.', 'You sometimes follow a schedule.', 'You usually stick to your schedule.', 'Your life is color-coded and timestamped.'),
  ('019e4f65-b591-702b-aa07-b3a2b760e2cc', 'Do you get irritated easily?', 'plus', 'neuroticism', 'It takes a lot to irritate you.', 'You stay calm most of the time.', 'You get irritated occasionally.', 'You get irritated quite easily.', 'Everything and everyone irritates you.'),
  ('019e4f65-b592-702c-afe0-b10baf0dac51', 'Do you spend time reflecting on things?', 'plus', 'openness', 'You live completely in the moment.', 'You reflect occasionally.', 'You think about things sometimes.', 'You enjoy reflecting on life.', 'Your brain is a 24/7 philosophy podcast.'),
  ('019e4f65-b593-702d-9c14-12f60f7ea1cc', 'Are you quiet around strangers?', 'minus', 'extraversion', 'You become a social butterfly with strangers.', 'You warm up quickly.', 'You''re somewhat quiet at first.', 'You tend to be quiet around strangers.', 'You go full silent mode with new people.'),
  ('019e4f65-b594-702e-8548-0f0d6c60d68d', 'Do you make people feel at ease?', 'plus', 'agreeableness', 'People feel awkward around you.', 'You''re neutral in social comfort.', 'You can make people comfortable sometimes.', 'You''re good at making others feel at ease.', 'You''re a walking comfort blanket.'),
  ('019e4f65-b595-702f-9cf4-73a941910577', 'Are you exacting in your work?', 'plus', 'conscientiousness', 'You do the bare minimum.', 'You do decent work.', 'You''re reasonably careful.', 'You pay close attention to quality.', 'Your work is obsessively precise.'),
  ('019e4f65-b596-7030-bb9e-2904d5af5c4a', 'Do you often feel blue?', 'plus', 'neuroticism', 'You''re almost always in a good mood.', 'You rarely feel down.', 'You feel blue sometimes.', 'You often feel down.', 'Sadness is your default setting.'),
  ('019e4f65-b597-7031-9817-02b0ac6effc7', 'Are you full of ideas?', 'plus', 'openness', 'Your idea tank is usually empty.', 'You get ideas now and then.', 'You have a decent number of ideas.', 'You''re often full of ideas.', 'Your brain throws idea parties every hour.')
;
